```json
{
  "module": "lead-management",
  "version": "1.0.0",
  "entities": [
    {
      "name": "lead",
      "label": "Lead",
      "pluralLabel": "Leads",
      "description": "Sales lead with status and revenue tracking",
      "fields": [
        {
          "name": "id",
          "label": "ID",
          "type": "text",
          "required": true,
          "unique": true
        },
        {
          "name": "name",
          "label": "Lead Name",
          "type": "text",
          "required": true
        },
        {
          "name": "status",
          "label": "Status",
          "type": "select",
          "options": ["New", "Qualified", "Negotiating", "Closed-Won", "Closed-Lost"],
          "required": true,
          "default": "New"
        },
        {
          "name": "revenue",
          "label": "Revenue",
          "type": "currency",
          "required": false
        },
        {
          "name": "email",
          "label": "Email",
          "type": "email"
        }
      ],
      "timestamps": true,
      "softDelete": true,
      "validations": [
        {
          "name": "closed_won_revenue_check",
          "description": "Status cannot be Closed-Won if Revenue is null or zero",
          "rule": "if(status == 'Closed-Won' && (revenue == null || revenue == 0)) then error('Revenue required for Closed-Won status')"
        }
      ]
    }
  ],
  "views": [
    {
      "name": "lead_table",
      "label": "Leads Table",
      "entity": "lead",
      "type": "table",
      "layout": ["name", "status", "revenue", "email"]
    },
    {
      "name": "lead_form",
      "label": "Lead Form",
      "entity": "lead",
      "type": "form",
      "layout": ["name", "status", "revenue", "email"]
    }
  ],
  "actions": [],
  "automations": [],
  "navigation": [
    {
      "label": "Leads",
      "icon": "users",
      "view": "lead_table"
    }
  ]
}
